#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    int n;
   // cout << "Enter the number of jobs: ";
    cin >> n;

    vector<int> jobIds(n), deadlines(n), profits(n);

    for (int i = 0; i < n; i++) {
        cin >> jobIds[i] >> deadlines[i] >> profits[i];
    }

    // Create an array of indices for sorting based on profit
    vector<int> indices(n);
    for (int i = 0; i < n; i++) {
        indices[i] = i;
    }

    // Sort indices based on profits in descending order
    sort(indices.begin(), indices.end(), [&](int a, int b) {
        return profits[a] > profits[b];
    });

    // Array to track free time slots and job sequence
    vector<bool> slot(n, false);
    vector<int> result(n, -1);

    // Schedule jobs
    int totalProfit = 0;

    for (int i = 0; i < n; i++) {
        int jobIndex = indices[i];
        // Try to find a free slot for this job, starting from its deadline
        for (int j = min(n, deadlines[jobIndex]) - 1; j >= 0; j--) {
            if (!slot[j]) {
                slot[j] = true; // Mark the slot as filled
                result[j] = jobIndex; // Assign this job to the slot
                cout << jobIds[jobIndex] << " "; // Print job as it is scheduled
                totalProfit += profits[jobIndex]; // Add the profit of this job
                break;
            }
        }
    }

    cout << totalProfit << endl;

    return 0;
}

