#include <stdio.h>

// Function to swap two rows in the jobs array
void swap(int jobs[][3], int i, int j) {
    for (int k = 0; k < 3; k++) {
        int temp = jobs[i][k];
        jobs[i][k] = jobs[j][k];
        jobs[j][k] = temp;
    }
}

// Bubble sort function to sort based on profit in descending order
void bubbleSort(int jobs[][3], int n) {
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (jobs[j][2] < jobs[j + 1][2]) { // Compare profits
                swap(jobs, j, j + 1);
            }
        }
    }
}

