import java.util.Scanner;

class Codechef {

    public static void main(String[] args) {
        // Input reading
        Scanner sc = new Scanner(System.in);

        // Number of jobs
        int n = sc.nextInt();

        // Arrays to store job details: jobId, deadline, and profit
        int[] jobId = new int[n];
        int[] deadline = new int[n];
        int[] profit = new int[n];

        // Input job details
        for (int i = 0; i < n; i++) {
            jobId[i] = sc.nextInt();
            deadline[i] = sc.nextInt();
            profit[i] = sc.nextInt();
        }

        // Array to track if a slot is occupied
        boolean[] slot = new boolean[n];
        int totalProfit = 0;

        // Array to store jobs sorted by profit
        int[] order = new int[n];

        // Sorting jobs based on profit (in descending order)
        for (int i = 0; i < n; i++) {
            order[i] = i;
        }

        // Simple bubble sort to sort jobs by profit in descending order
        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < n - 1 - i; j++) {
                if (profit[order[j]] < profit[order[j + 1]]) {
                    // Swap the jobs based on profit
                    int temp = order[j];
                    order[j] = order[j + 1];
                    order[j + 1] = temp;
                }
            }
        }

        // Schedule jobs to maximize profit
        for (int i = 0; i < n; i++) {
            int job = order[i]; // Current job index
            // Try to find a slot for the current job
            for (int j = Math.min(n, deadline[job]) - 1; j >= 0; j--) {
                if (!slot[j]) {
                    slot[j] = true; // Mark the slot as filled
                    System.out.print(jobId[job] + " "); // Print the job ID
                    totalProfit += profit[job]; // Add the profit of this job
                    break;
                }
            }
        }

        // Output total profit
        System.out.println( totalProfit);

        sc.close();
    }
}

