rl.on('line', (line) => {
  input.push(line.trim());
});

rl.on('close', () => {
  let [m, n] = input[0].split(' ').map(Number);
  let a = [];

  for (let i = 1; i <= m; i++) {
    a.push(input[i].split(' ').map(Number));
  }

  let [_n, p] = input[m + 1].split(' ').map(Number);

  let b = [];
  for (let i = m + 2; i <= m + 1 + _n; i++) {
    b.push(input[i].split(' ').map(Number));
  }

  function multiplyMatrices(matrixA, matrixB) {
    const rowsA = matrixA.length;
    const colsA = matrixA[0].length;
    const rowsB = matrixB.length;
    const colsB = matrixB[0].length;

    if (colsA !== rowsB) {
      throw new Error("Matrix multiplication not possible: column count of matrix A must equal row count of matrix B.");
    }

    let result = Array.from({ length: rowsA }, () => Array(colsB).fill(0));

    for (let i = 0; i < rowsA; i++) {
      for (let j = 0; j < colsB; j++) {
        for (let k = 0; k < colsA; k++) {
          result[i][j] += matrixA[i][k] * matrixB[k][j];
        }
      }
    }

    return result;
  }

  try {
    const result = multiplyMatrices(a, b);
    result.forEach(row => console.log(row.join(' ')));
  } catch (error) {
    console.error(error.message);
  }
});
